# 022-quasi_geo-evidence.R
# Generated by behavior-preserving split of quasi_geo_test.R.

qgt_best_use <- function(x) {
  x <- as.character(x %||% character())
  if (!length(x)) return(NA_character_)
  ranks <- c("ignore/filter" = 0, diagnostic_only = 1, directional_prior = 2, calibration = 3)
  vals <- ranks[x]
  vals[is.na(vals)] <- -1
  x[which.max(vals)]
}
qgt_best_band <- function(x) {
  x <- as.character(x %||% character())
  if (!length(x)) return(NA_character_)
  ranks <- c(weak = 0, diagnostic = 1, directional = 2, strong = 3, very_strong = 4)
  vals <- ranks[x]
  vals[is.na(vals)] <- -1
  x[which.max(vals)]
}
qgt_top_reason_text <- function(x, n = 4L) {
  vals <- trimws(as.character(x %||% character()))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (!length(vals)) return("")
  vals <- unlist(strsplit(vals, "\\||;|,", perl = TRUE), use.names = FALSE)
  vals <- trimws(vals)
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (!length(vals)) return("")
  tab <- sort(table(vals), decreasing = TRUE)
  paste(head(names(tab), n), collapse = "|")
}
qgt_recommended_action <- function(recommended_use,
                                   channel_specific_usable_n,
                                   bundle_usable_n,
                                   diagnostic_event_n,
                                   max_score,
                                   blocker_reasons = "") {
  if (identical(recommended_use, "calibration") && bundle_usable_n > 0L && channel_specific_usable_n == 0L) return("bundle_calibration_candidate")
  if (identical(recommended_use, "calibration")) return("calibration_candidate")
  if (identical(recommended_use, "directional_prior") && channel_specific_usable_n > 0L) return("channel_directional_prior")
  if (bundle_usable_n > 0L) return("bundle_or_campaign_prior_only")
  if (diagnostic_event_n > 0L && is.finite(max_score) && max_score >= 35) return("diagnostic_review")
  if (nzchar(as.character(blocker_reasons %||% ""))) return("blocked_or_not_geo_identifiable")
  "insufficient_evidence"
}
qgt_build_evidence_summary <- function(event_results, scope = c("overall", "variable", "estimand")) {
  scope <- match.arg(scope)
  if (is.null(event_results) || !nrow(event_results)) return(qgt_empty_evidence_summary())
  dt <- copy(event_results)
  for (cc in c("recommended_use", "confidence_band", "estimand_level", "bundle_name", "downgrade_reasons", "blocker_reasons")) {
    if (!cc %in% names(dt)) dt[, (cc) := ""]
  }
  for (cc in c("channel_specific_usable", "bundle_usable")) {
    if (!cc %in% names(dt)) dt[, (cc) := FALSE]
  }
  if (!"evidence_score_0_100" %in% names(dt)) dt[, evidence_score_0_100 := evidence_score]
  if (!"marginal_response" %in% names(dt)) dt[, marginal_response := NA_real_]
  if (!"roi_like" %in% names(dt)) dt[, roi_like := NA_real_]
  if (!"cost_per_incremental_outcome" %in% names(dt)) dt[, cost_per_incremental_outcome := NA_real_]
  if (!"incremental_outcome" %in% names(dt)) dt[, incremental_outcome := NA_real_]
  by_cols <- switch(
    scope,
    overall = character(),
    variable = "variable",
    estimand = c("estimand_level", "bundle_name")
  )
  summarize <- function(x) {
    best_use <- qgt_best_use(x$recommended_use)
    best_band <- qgt_best_band(x$confidence_band)
    chan_n <- sum(x$channel_specific_usable %in% TRUE, na.rm = TRUE)
    bundle_n <- sum(x$bundle_usable %in% TRUE, na.rm = TRUE)
    diag_n <- sum(x$recommended_use == "diagnostic_only", na.rm = TRUE)
    max_score <- if (any(is.finite(x$evidence_score_0_100))) max(x$evidence_score_0_100, na.rm = TRUE) else NA_real_
    blockers <- qgt_top_reason_text(x$blocker_reasons)
    data.table(
      event_n = nrow(x),
      estimable_event_n = sum(is.finite(x$incremental_outcome), na.rm = TRUE),
      calibration_event_n = sum(x$recommended_use == "calibration", na.rm = TRUE),
      directional_prior_event_n = sum(x$recommended_use == "directional_prior", na.rm = TRUE),
      diagnostic_event_n = diag_n,
      ignored_event_n = sum(x$recommended_use == "ignore/filter", na.rm = TRUE),
      channel_specific_usable_n = chan_n,
      bundle_usable_n = bundle_n,
      max_evidence_score = max_score,
      mean_evidence_score = mean(x$evidence_score_0_100, na.rm = TRUE),
      best_recommended_use = best_use,
      best_confidence_band = best_band,
      median_marginal_response = stats::median(x$marginal_response, na.rm = TRUE),
      median_roi_like = stats::median(x$roi_like, na.rm = TRUE),
      median_cost_per_outcome = stats::median(x$cost_per_incremental_outcome, na.rm = TRUE),
      top_downgrade_reasons = qgt_top_reason_text(x$downgrade_reasons),
      top_blocker_reasons = blockers,
      recommended_analyst_action = qgt_recommended_action(best_use, chan_n, bundle_n, diag_n, max_score, blockers)
    )
  }
  out <- if (length(by_cols)) {
    dt[, summarize(.SD), by = by_cols]
  } else {
    summarize(dt)
  }
  out[, summary_scope := scope]
  for (cc in c("variable", "estimand_level", "bundle_name")) {
    if (!cc %in% names(out)) out[, (cc) := NA_character_]
  }
  data.table::setcolorder(out, names(qgt_empty_evidence_summary()))
  out[]
}
qgt_classify_evidence_events <- function(estimates) {
  if (is.null(estimates)) return(estimates)
  out <- copy(estimates)
  if (!nrow(out)) {
    for (cc in c("moved_channels", "estimand_level", "bundle_name", "downgrade_reasons", "blocker_reasons",
                 "recommended_use", "confidence_band", "co_moving_channel_list")) {
      if (!cc %in% names(out)) out[, (cc) := character()]
    }
    for (cc in c("moved_channel_count", "co_moving_same_direction_n", "co_moving_opposite_direction_n")) {
      if (!cc %in% names(out)) out[, (cc) := integer()]
    }
    for (cc in c("channel_specific_usable", "bundle_usable", "bundle_direction_consistent",
                 "donor_contamination", "other_media_contamination", "counterfactual_fallback_success")) {
      if (!cc %in% names(out)) out[, (cc) := logical()]
    }
    for (cc in c("evidence_score_0_100", "pre_fit_quality", "placebo_strength", "mde_power",
                 "donor_quality", "sign_consistency", "shock_strength",
                 "bundle_incremental_outcome", "bundle_incremental_spend",
                 "bundle_return_prior", "bundle_cost_per_outcome")) {
      if (!cc %in% names(out)) out[, (cc) := numeric()]
    }
    if (!"false_positive_check" %in% names(out)) out[, false_positive_check := character()]
    return(out[])
  }
  for (cc in c("co_moving_media_summary", "diagnostic_reason", "effect_direction", "evidence_tier", "selected_counterfactual_method")) {
    if (!cc %in% names(out)) out[, (cc) := ""]
  }
  if (!"incremental_outcome" %in% names(out)) out[, incremental_outcome := NA_real_]
  if (!"co_moving_channel_list" %in% names(out)) out[, co_moving_channel_list := ""]
  if (!"co_moving_same_direction_n" %in% names(out)) out[, co_moving_same_direction_n := 0L]
  if (!"co_moving_opposite_direction_n" %in% names(out)) out[, co_moving_opposite_direction_n := 0L]
  if (!"bundle_direction_consistent" %in% names(out)) out[, bundle_direction_consistent := TRUE]
  for (cc in c("bundle_incremental_support", "bundle_incremental_outcome_raw", "bundle_incremental_spend_raw",
               "bundle_return_prior_raw", "bundle_cost_per_outcome_raw")) {
    if (!cc %in% names(out)) out[, (cc) := NA_real_]
  }
  out[, moved_channels := {
    primary <- as.character(variable)
    extra <- strsplit(as.character(co_moving_channel_list), "\\|", fixed = FALSE)
    vapply(seq_along(primary), function(i) {
      vals <- unique(c(primary[i], extra[[i]]))
      vals <- vals[!is.na(vals) & nzchar(vals)]
      paste(sort(vals), collapse = "|")
    }, character(1))
  }]
  out[, moved_channel_count := 1L + fifelse(is.finite(co_moving_channel_n), as.integer(co_moving_channel_n), 0L)]
  out[, estimand_level := data.table::fcase(
    grepl("national_repeated_media", diagnostic_reason, fixed = TRUE), "diagnostic",
    moved_channel_count > 1L, "bundle",
    default = "channel"
  )]
  out[, bundle_name := fifelse(estimand_level == "bundle", moved_channels, NA_character_)]
  out[, channel_specific_usable := estimand_level == "channel" &
        effect_direction == "positive_media_effect" &
        evidence_tier %in% c("strong_quasi_geo", "moderate_quasi_geo") &
        !grepl("other_media_moved|co_moving_media_signal|weak_pre_fit|large_pre_period_placebo_lift|national_repeated_media", diagnostic_reason)]
  out[, bundle_usable := estimand_level == "bundle" &
        effect_direction == "positive_media_effect" &
        bundle_direction_consistent %in% TRUE &
        evidence_tier %in% c("strong_quasi_geo", "moderate_quasi_geo") &
        !grepl("weak_pre_fit|large_pre_period_placebo_lift|national_repeated_media|opposite_direction_co_moving_media", diagnostic_reason)]
  out[, downgrade_reasons := diagnostic_reason]
  out[, counterfactual_fallback_success := selected_counterfactual_method %in% c("time_based_regression", "difference_in_differences") &
        is.finite(incremental_outcome)]
  out[, hard_blocker_reason := fifelse(
    grepl("national_repeated_media|no_unaffected_donor_geos_same_channel|no_candidate_donor_geos|treated_geo_missing_pre_period|no_donor_data_in_pre_period|insufficient_pre_or_post_window|counterfactual_estimation_failed|incomplete_synthetic_control_rows", diagnostic_reason),
    diagnostic_reason,
    ""
  )]
  out[, synthetic_only_blocker_reason := fifelse(
    grepl("synthetic_control_weights_failed", diagnostic_reason, fixed = TRUE) & !counterfactual_fallback_success,
    diagnostic_reason,
    ""
  )]
  out[, blocker_reasons := fifelse(nzchar(hard_blocker_reason), hard_blocker_reason, synthetic_only_blocker_reason)]
  out[, recommended_use := data.table::fcase(
    nzchar(blocker_reasons), "diagnostic_only",
    channel_specific_usable & evidence_tier == "strong_quasi_geo" & !grepl("overlapping_events", diagnostic_reason, fixed = TRUE), "calibration",
    bundle_usable & evidence_tier == "strong_quasi_geo", "calibration",
    channel_specific_usable, "directional_prior",
    bundle_usable, "directional_prior",
    evidence_score <= 0 | grepl("not_estimable", evidence_tier, fixed = TRUE), "ignore/filter",
    default = "diagnostic_only"
  )]
  out[, evidence_score_0_100 := evidence_score]
  out[, confidence_band := data.table::fcase(
    recommended_use == "calibration" & evidence_score >= 85, "very_strong",
    recommended_use %in% c("calibration", "directional_prior") & evidence_score >= 70, "strong",
    recommended_use == "directional_prior", "directional",
    recommended_use == "diagnostic_only", "diagnostic",
    default = "weak"
  )]
  if (!"donor_placebo_strength" %in% names(out)) out[, donor_placebo_strength := NA_real_]
  out[, `:=`(
    pre_fit_quality = pre_fit_score,
    placebo_strength = {
      pre_placebo_strength <- fifelse(is.finite(placebo_lift_abs_ratio), qgt_clip(1 - placebo_lift_abs_ratio, 0, 1), NA_real_)
      fifelse(is.finite(pre_placebo_strength) & is.finite(donor_placebo_strength),
              pmin(pre_placebo_strength, donor_placebo_strength),
              fifelse(is.finite(pre_placebo_strength), pre_placebo_strength, donor_placebo_strength))
    },
    false_positive_check = fifelse(
      (is.finite(placebo_lift_abs_ratio) & placebo_lift_abs_ratio <= 0.5) &
        (!is.finite(donor_placebo_strength) | donor_placebo_strength >= 0.60),
      "passed",
      "review"
    ),
    mde_power = power_score,
    donor_quality = qgt_clip((pmin(donor_n, 8) / 8) * (1 - fifelse(is.finite(donor_weight_max), qgt_clip(donor_weight_max - 0.5, 0, 0.5) / 0.5, 0)), 0, 1),
    donor_contamination = grepl("donor_media_contamination", diagnostic_reason, fixed = TRUE),
    other_media_contamination = co_moving_channel_n > 0,
    sign_consistency = direction_consistency_score,
    shock_strength = pct_change_abs,
    bundle_incremental_outcome = fifelse(estimand_level == "bundle", bundle_incremental_outcome_raw, NA_real_),
    bundle_incremental_spend = fifelse(estimand_level == "bundle", bundle_incremental_spend_raw, NA_real_),
    bundle_return_prior = fifelse(estimand_level == "bundle", bundle_return_prior_raw, NA_real_),
    bundle_cost_per_outcome = fifelse(estimand_level == "bundle", bundle_cost_per_outcome_raw, NA_real_)
  )]
  out[, c("hard_blocker_reason", "synthetic_only_blocker_reason") := NULL]
  out[]
}

qgt_national_repeated_media_diagnostics <- function(dt,
                                                    date_col,
                                                    geo_col,
                                                    vm,
                                                    tolerance = 1e-8) {
  if (is.null(vm) || !nrow(vm)) return(qgt_empty_event_estimates())
  rows <- lapply(seq_len(nrow(vm)), function(i) {
    cc <- vm$modeled_x_col[i]
    if (!cc %in% names(dt)) return(NULL)
    by_date <- dt[, .(
      geo_n = data.table::uniqueN(get(geo_col)),
      sd_x = stats::sd(qgt_num(get(cc)), na.rm = TRUE),
      mean_x = mean(abs(qgt_num(get(cc))), na.rm = TRUE)
    ), by = date_col]
    comparable <- by_date[geo_n >= 2 & is.finite(mean_x)]
    if (!nrow(comparable)) return(NULL)
    repeated_share <- comparable[, mean(!is.finite(sd_x) | sd_x <= pmax(tolerance, mean_x * tolerance), na.rm = TRUE)]
    if (!is.finite(repeated_share) || repeated_share < 0.95) return(NULL)
    template <- data.table(
      event_id = paste0("national_repeated_media__", vm$variable[i]),
      variable = vm$variable[i],
      geo = "ALL",
      event_start = min(dt[[date_col]], na.rm = TRUE),
      event_end = max(dt[[date_col]], na.rm = TRUE),
      starting_support = NA_real_,
      event_media = NA_real_,
      signed_treatment_intensity = NA_real_,
      abs_change = NA_real_,
      change_abs = NA_real_,
      pct_change = NA_real_,
      pct_change_abs = NA_real_,
      robust_z = NA_real_,
      ramp_direction = "none",
      event_type = "national_repeated_media",
      media_cutoff_flag = FALSE
    )
    out <- qgt_event_not_estimable(template, "national_repeated_media_not_geo_identifiable", method = "diagnostic")
    out[, `:=`(
      evidence_score = 0,
      evidence_score_0_100 = 0,
      quality_score = 0,
      moved_channels = as.character(variable),
      moved_channel_count = 1L,
      estimand_level = "diagnostic",
      bundle_name = NA_character_,
      channel_specific_usable = FALSE,
      bundle_usable = FALSE,
      downgrade_reasons = diagnostic_reason,
      blocker_reasons = diagnostic_reason,
      recommended_use = "diagnostic_only",
    pre_fit_quality = NA_real_,
    placebo_strength = NA_real_,
    donor_placebo_strength = NA_real_,
    false_positive_check = "not_applicable",
      mde_power = NA_real_,
      donor_quality = NA_real_,
      donor_contamination = NA,
      other_media_contamination = NA,
      sign_consistency = NA_real_,
      shock_strength = NA_real_,
      bundle_incremental_outcome = NA_real_,
      bundle_incremental_spend = NA_real_,
      bundle_return_prior = NA_real_,
      bundle_cost_per_outcome = NA_real_
    )]
    out
  })
  out <- rbindlist(rows, use.names = TRUE, fill = TRUE)
  if (is.null(out)) qgt_empty_event_estimates() else out[]
}
